diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9df08553d86e..d049a7d03ddf 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8790,6 +8790,121 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

+  // fcmp (fptrunc X), C -> fcmp X, C2
+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    const APFloat *C;
+    if (match(Op1, m_APFloat(C))) {
+      Type *SrcTy = X->getType();
+      Type *DstTy = Op0->getType();
+      unsigned SrcBits = SrcTy->getScalarSizeInBits();
+      unsigned DstBits = DstTy->getScalarSizeInBits();
+
+      // Only when truncating from larger to smaller FP type
+      if (SrcBits > DstBits) {
+        const fltSemantics &SrcSem = SrcTy->getScalarType()->getFltSemantics();
+        const fltSemantics &DstSem = DstTy->getScalarType()->getFltSemantics();
+
+        // Only handle finite non-zero constants for now
+        if (C->isFinite() && !C->isZero()) {
+          // Convert C to the wider type (exact, since float->double is exact)
+          APFloat WideC = *C;
+          bool Lossy;
+          WideC.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+          // Conversion from narrower to wider should never be lossy
+          (void)Lossy;
+
+          // Compute the ulp of the narrow type at C
+          // nextUp in narrow type
+          APFloat CNarrow = *C;
+          CNarrow.next(false); // nextUp
+          // If C is max finite value, nextUp gives infinity.
+          // For ppc_fp128 (DoubleAPFloat), next() on infinity crashes.
+          // Bail out for ppc_fp128 to avoid the crash.
+          if (CNarrow.isInfinity() && SrcTy->getScalarType()->isPPC_FP128Ty())
+            return nullptr;
+          // Convert to wide type
+          APFloat WideCNext = CNarrow;
+          WideCNext.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+          
+          // ulp = WideCNext - WideC
+          APFloat Ulp = WideCNext;
+          Ulp.subtract(WideC, APFloat::rmNearestTiesToEven);
+          
+          // half_ulp = ulp / 2
+          APFloat HalfUlp = Ulp;
+          // Divide by 2: multiply by 0.5
+          APFloat Half(0.5);
+          bool HalfLossy;
+          Half.convert(SrcSem, APFloat::rmNearestTiesToEven, &HalfLossy);
+          HalfUlp.multiply(Half, APFloat::rmNearestTiesToEven);
+
+          // Check if C is "even" (mantissa LSB is 0)
+          APInt Cbits = C->bitcastToAPInt();
+          bool IsEven = (Cbits.getLoBits(1) == 0);
+
+          // Compute the boundary based on predicate
+          APFloat Bound(SrcSem);
+          switch (Pred) {
+          case FCmpInst::FCMP_OGE:
+          case FCmpInst::FCMP_UGE:
+            // Smallest double that rounds to >= C
+            Bound = WideC;
+            Bound.subtract(HalfUlp, APFloat::rmNearestTiesToEven);
+            if (!IsEven) {
+              // The boundary is excluded; take nextUp
+              Bound.next(false);
+            }
+            break;
+          case FCmpInst::FCMP_OGT:
+          case FCmpInst::FCMP_UGT:
+            // Smallest double that rounds to > C
+            if (IsEven) {
+              Bound = WideC;
+              Bound.add(HalfUlp, APFloat::rmNearestTiesToEven);
+            } else {
+              Bound = WideC;
+              Bound.add(HalfUlp, APFloat::rmNearestTiesToEven);
+              Bound.next(true); // nextDown
+            }
+            break;
+          case FCmpInst::FCMP_OLE:
+          case FCmpInst::FCMP_ULE:
+            // Largest double that rounds to <= C
+            if (IsEven) {
+              Bound = WideC;
+              Bound.add(HalfUlp, APFloat::rmNearestTiesToEven);
+            } else {
+              Bound = WideC;
+              Bound.add(HalfUlp, APFloat::rmNearestTiesToEven);
+              Bound.next(true); // nextDown
+            }
+            break;
+          case FCmpInst::FCMP_OLT:
+          case FCmpInst::FCMP_ULT:
+            // Largest double that rounds to < C
+            if (IsEven) {
+              Bound = WideC;
+              Bound.subtract(HalfUlp, APFloat::rmNearestTiesToEven);
+            } else {
+              Bound = WideC;
+              Bound.subtract(HalfUlp, APFloat::rmNearestTiesToEven);
+              Bound.next(false); // nextUp
+            }
+            break;
+          default:
+            // Unsupported predicate
+            break;
+          }
+
+          if (!Bound.isZero()) { // We set a bound
+            Constant *NewC = ConstantFP::get(SrcTy, Bound);
+            return new FCmpInst(Pred, X, NewC, "", &I);
+          }
+        }
+      }
+    }
+  }
+
   // Convert a sign-bit test of an FP value into a cast and integer compare.
   // TODO: Simplify if the copysign constant is 0.0 or NaN.
   // TODO: Handle non-zero compare constants.

